{
 "level": "B1",
 "intro": "In this topic, you will learn in detail the <strong>Present Continuous Passive</strong>: how to form this form, when to use it, and how it differs from the Present Simple Passive.",
 "rules": [
 {
 "label": "Formula",
 "color": "emerald",
 "text": "<strong>Subject + am/is/are + being + V3</strong>:",
 "example": "The house is being painted right now."
 },
 {
 "label": "Denial",
 "color": "rose",
 "text": "<strong>Subject + am/is/are + not + being + V3</strong>:",
 "example": "The report is not being written now."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "<strong>Am/Is/Are + Subject + being + V3?</strong>:",
 "example": "Is the project being developed?"
 }
 ]
}

{
 "title": "1. Structure of the Present Continuous Passive",
 "intro": "The form of the verb <strong>be</strong> depends on the subject, and <strong>being</strong> remains unchanged:",
 "items": [
 {
 "label": "I",
 "title": "am being + V3",
 "subtitle": "I am being interviewed now. - I am being interviewed now."
 },
 {
 "label": "He/She/It",
 "title": "is being + V3",
 "subtitle": "The car is being repaired. - The car is being repaired."
 },
 {
 "label": "You/We/They",
 "title": "are being + V3",
 "subtitle": "The documents are being checked. — Documents are being checked."
 },
 {
 "label": "Key",
 "title": "being is an unchanging part",
 "subtitle": "being always precedes V3."
 }
 ]
}

{
 "title": "2. Affirmative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "Word order: <strong>Subject + am/is/are + being + V3 (+ by agent)</strong>",
 "examples": [
 {
 "en": "The house is being painted at the moment.",
 "ua": "The house is being painted at the moment."
 },
 {
 "en": "The documents are being prepared right now.",
 "ua": "The documents are being prepared right now."
 },
 {
 "en": "I am being trained for the new position.",
 "ua": "I am being trained for the new position."
 },
 {
 "en": "The road is being repaired this week.",
 "ua": "The road is being repaired this week."
 }
 ]
 },
 {
 "label": "Temporary processes",
 "color": "sky",
 "description": "For actions that <strong>last for a certain period of time</strong>:",
 "examples": [
 {
 "en": "A new system is being installed this month.",
 "ua": "A new system is being installed this month."
 },
 {
 "en": "The building is being renovated.",
 "ua": "The building is being renovated."
 },
 {
 "en": "New software is being tested at the moment.",
 "ua": "New software is being tested at the moment."
 }
 ]
 }
 ]
}

{
 "title": "3. When to use Present Continuous Passive?",
 "sections": [
 {
 "label": "Action right now",
 "color": "emerald",
 "description": "For actions <strong>occurring at the moment of speech</strong>:",
 "examples": [
 {
 "en": "The dinner is being cooked right now.",
 "ua": "The dinner is being cooked right now."
 },
 {
 "en": "The meeting is being held at the moment.",
 "ua": "The meeting is being held at the moment."
 },
 {
 "en": "Your order is being processed.",
 "ua": "Your order is being processed."
 }
 ]
 },
 {
 "label": "Temporary situations",
 "color": "blue",
 "description": "For actions that <strong>last for a certain period</strong>, but not permanently:",
 "examples": [
 {
 "en": "The bridge is being constructed this year.",
 "ua": "The bridge is being constructed this year."
 },
 {
 "en": "New employees are being trained this month.",
 "ua": "New employees are being trained this month."
 },
 {
 "en": "The project is being developed at present.",
 "ua": "The project is being developed at present."
 }
 ]
 },
 {
 "label": "Changes and trends",
 "color": "amber",
 "description": "To describe the <strong>current changes</strong>:",
 "examples": [
 {
 "en": "More and more trees are being planted.",
 "ua": "More and more trees are being planted."
 },
 {
 "en": "The old system is being replaced gradually.",
 "ua": "The old system is being replaced gradually."
 },
 {
 "en": "Electric cars are being promoted heavily.",
 "ua": "Electric cars are being promoted heavily."
 }
 ]
 }
 ]
}

{
 "title": "4. Negative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "rose",
 "description": "Add <strong>not</strong> after am/is/are: <strong>Subject + am/is/are + not + being + V3</strong>",
 "examples": [
 {
 "en": "The report is not being written at the moment.",
 "ua": "The report is not being written at the moment."
 },
 {
 "en": "The rooms are not being cleaned today.",
 "ua": "The rooms are not being cleaned today."
 },
 {
 "en": "I am not being considered for the job.",
 "ua": "I am not being considered for the job."
 },
 {
 "en": "The problem is not being addressed.",
 "ua": "The problem is not being addressed."
 }
 ]
 },
 {
 "label": "Abbreviated forms",
 "color": "amber",
 "description": "Colloquially: <strong>isn't being / aren't being</strong>",
 "examples": [
 {
 "en": "The car isn't being repaired today.",
 "ua": "The car isn't being repaired today."
 },
 {
 "en": "The packages aren't being delivered now.",
 "ua": "The packages aren't being delivered now."
 },
 {
 "en": "The issue isn't being investigated.",
 "ua": "The issue isn't being investigated."
 }
 ]
 }
 ]
}

{
 "title": "5. Interrogative sentences",
 "sections": [
 {
 "label": "Yes/No question",
 "color": "blue",
 "description": "<strong>Am/Is/Are</strong> comes first: <strong>Am/Is/Are + Subject + being + V3?</strong>",
 "examples": [
 {
 "en": "Is the house being painted?",
 "ua": "Is the house being painted?"
 },
 {
 "en": "Are the documents being checked?",
 "ua": "Are the documents being checked?"
 },
 {
 "en": "Am I being tested?",
 "ua": "Am I being tested?"
 },
 {
 "en": "Is the project being developed?",
 "ua": "Is the project being developed?"
 }
 ]
 },
 {
 "label": "Wh question",
 "color": "sky",
 "description": "<strong>Wh-word + am/is/are + Subject + being + V3?</strong>",
 "examples": [
 {
 "en": "What is being built there?",
 "ua": "What is being built there?"
 },
 {
 "en": "Why is the road being closed?",
 "ua": "Why is the road being closed?"
 },
 {
 "en": "Where are the tests being conducted?",
 "ua": "Where are the tests being conducted?"
 },
 {
 "en": "How is the problem being solved?",
 "ua": "How is the problem being solved?"
 }
 ]
 },
 {
 "label": "Short answers",
 "color": "amber",
 "description": "Answers with <strong>Yes/No + pronoun + am/is/are (not)</strong>:",
 "examples": [
 {
 "en": "Is the car being repaired? — Yes, it is. / No, it isn't.",
 "ua": "Is the car being repaired? — Yes, it is. / No, it isn't."
 },
 {
 "en": "Are they being interviewed? — Yes, they are. / No, they aren't.",
 "ua": "Are they being interviewed? — Yes, they are. / No, they aren't."
 }
 ]
 }
 ]
}

{
 "title": "6. Comparison of Active vs Passive in Present Continuous",
 "intro": "How to turn an active sentence into a passive:",
 "rows": [
 {
 "en": "Active: They are painting the house now.",
 "ua": "Active: They are painting the house now.",
 "note": "→ Passive: The house is being painted now."
 },
 {
 "en": "Active: The manager is checking the documents.",
 "ua": "Active: The manager is checking the documents.",
 "note": "→ Passive: The documents are being checked."
 },
 {
 "en": "Active: Workers are repairing the road.",
 "ua": "Active: Workers are repairing the road.",
 "note": "→ Passive: The road is being repaired."
 },
 {
 "en": "Active: Someone is interviewing me.",
 "ua": "Active: Someone is interviewing me.",
 "note": "→ Passive: I am being interviewed."
 }
 ],
 "warning": "📌 Time markers (now, at the moment, currently) remain!"
}

{
 "title": "7. Present Simple Passive vs Present Continuous Passive",
 "intro": "Comparison of the two forms - regular actions vs actions right now:",
 "rows": [
 {
 "en": "The house is cleaned every week.",
 "ua": "The house is cleaned every week.",
 "note": "vs: The house is being cleaned now. - The house is being cleaned now."
 },
 {
 "en": "Cars are made in Germany.",
 "ua": "Cars are made in Germany.",
 "note": "vs: A car is being made for me. — The car is now being made for me."
 },
 {
 "en": "The report is prepared monthly.",
 "ua": "The report is prepared monthly.",
 "note": "vs: The report is being prepared now. — The report is currently being prepared."
 }
 ],
 "warning": "📌 Present Simple = regularly, always. Present Continuous = now, at this moment."
}

{
 "title": "8. Time markers for the Present Continuous Passive",
 "intro": "Typical words and expressions indicating the Present Continuous:",
 "items": [
 {
 "label": "Now",
 "title": "now, right now, at the moment, currently",
 "subtitle": "The report is being written right now."
 },
 {
 "label": "Today",
 "title": "today, this morning, this afternoon",
 "subtitle": "The meeting is being held this afternoon."
 },
 {
 "label": "This period",
 "title": "this week, this month, this year",
 "subtitle": "A new bridge is being built this year."
 },
 {
 "label": "Temporarily",
 "title": "at present, for the time being, temporarily",
 "subtitle": "The office is being renovated at present."
 }
 ]
}

{
 "title": "9. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Skip being.",
 "wrong": "The house is painted now.",
 "right": "✅ The house is being painted now."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Incorrect word order.",
 "wrong": "The report being is written.",
 "right": "✅ The report is being written."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Using been instead of being.",
 "wrong": "The car is been repaired now.",
 "right": "✅ The car is being repaired now."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Confusion of Present Simple and Continuous.",
 "wrong": "The house is being cleaned every day.",
 "right": "✅ The house is cleaned every day."
 }
 ]
}
